import{_ as a,o as n,c as t,ae as i}from"./chunks/framework.B6gjLfeO.js";const w=JSON.parse('{"title":"New Branch Overview","description":"","frontmatter":{"title":"New Branch Overview","slug":"new-branch-overview"},"headers":[],"relativePath":"account-hub/new-branch-overview.md","filePath":"account-hub/new-branch-overview.md"}'),r={name:"account-hub/new-branch-overview.md"};function o(l,e,c,h,s,p){return n(),t("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>We’re improving your Branch experience with a full interface overhaul. You may notice some pages in the new Branch interface, and some on the legacy Branch interface. This depends on when you started using Branch.</p><p>Legacy Branch pages live at the <code>https://dashboard.branch.io</code> URL, whereas new Branch pages live at <code>https://app.branch.io</code>. The legacy platform redirects to the new platform where appropriate.</p><p>You can view documentation for the new experience in this section of the Branch Help Center.</p><h2 id="new-pages" tabindex="-1">New pages <a class="header-anchor" href="#new-pages" aria-label="Permalink to &quot;New pages&quot;">​</a></h2><p>Some pages you may see in the new Branch interface include:</p><ul><li><a href="./home-page-new.html">Home page</a></li><li><a href="./profile-new.html">Profile page</a></li><li><a href="./billing-new.html">Billing page</a></li><li><a href="./general-new.html">General page</a></li><li><a href="./security-access-new.html">Security &amp; Access page</a></li><li><a href="./link-controls-new.html">Link Controls page</a></li><li><a href="./attribution-page-new.html">Attribution page</a></li><li><a href="./testing-monitoring-new.html">Testing &amp; Monitoring page</a></li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>For information on new pages in Branch that are used for daily marketing workflows, visit <a href="./new-branch.html">Marketer Hub</a>.</p></div><h2 id="common-tasks" tabindex="-1">Common tasks <a class="header-anchor" href="#common-tasks" aria-label="Permalink to &quot;Common tasks&quot;">​</a></h2><p>View specific articles or article sections for common tasks in the new interface:</p><ul><li><a href="./billing-usage-new.html">View your account usage</a></li><li><a href="./general-new.html">Configure general app settings</a></li><li><a href="./attribution-page-new.html">Set attribution windows and enable Predictive Aggregate Measurement (PAM)</a></li><li><a href="./add-and-manage-test-devices-new.html">Add and manage your test devices</a></li><li><a href="./liveview-new.html">View Branch Events as they happen</a></li></ul>',11)])])}const u=a(r,[["render",o]]);export{w as __pageData,u as default};
